noncompliant:
public class Foo
{
    public void FetchResource(string uriString) { }
    public void FetchResource(Uri uri) { }
}

public class Bar
{
    public void DoSomething()
    {
        var foo = new Foo();
        foo.FetchResource("http://example.com"); // Noncompliant - string overload called when Uri overload exists
    }
}

compliant:
public class Foo
{
    public void FetchResource(string uriString) { }
    public void FetchResource(Uri uri) { }
}

public class Bar
{
    public void DoSomething()
    {
        var foo = new Foo();
        foo.FetchResource(new Uri("http://example.com")); // Compliant - Uri overload is used
    }
}
